function PetEquipIconNew:PetEquipIconNew(wndClass)
	self._refId = 0
	self._num = nil
	self._star = 0
	self._showGou = false
	self._showNum = false

	-----------------------------------------------------------------
	self._displayStar = 0
	self._displayShowIcon = nil
	self._displayShowIconBg = nil
	self._displayGray = false
	self._displayNum = 0

	self._displayName = nil
	self._displayColor = nil

	self._cacheStar = 0
end

function PetEquipIconNew:OnDestroy()

end
-----------------------------------------------------------------
function PetEquipIconNew:ResetIcon()
	BaseIconNew.ResetIcon(self)

	self._refId = 0
	self._num = nil
	self._star = 0
	self._showGou = false
	self._showNum = false
end

-----------------------------------------------------------------
function PetEquipIconNew:ApplyIconUI()
	BaseIconNew.ApplyIconUI(self)

	self:SetIcon(self._displayShowIcon)
	self:SetIconBg(self._displayShowIconBg)

	self:UpdateStarUI()

	self:SetGouTransVisible(self._showGou)
	self:SetEquipIconGray()

	self:SetNumUIVisible()

	self:ApplyLvTxt()
end

function PetEquipIconNew:OnInitTrans()

	local iconInst = self._iconInst
	self._uiNumTxtTrans = CS.FindTrans(iconInst,"NumTxt")
	self._uiStarTrans = CS.FindTrans(iconInst,"StarList")
	self._uiGouTrans = CS.FindTrans(iconInst,"GouImg")

	self:InitStartList()
end

-----------------------------------------------------------------
function PetEquipIconNew:EnableShowNum(bShow)
	self._showNum = bShow
	self:UpdateNumData()
end

function PetEquipIconNew:ShowNum(b)
	self._showNum = b

	self:UpdateNumData()

	if not self:IsIconValid() then return end

	self:SetNumUIVisible()

end

function PetEquipIconNew:UpdateNumData()
	if self._showNum and not self._num and gModelPet then
		local data = gModelPet:GetPetEquipByRefId(self._refId)
		local num = data and data:GetNum() or 0
		self._displayNum = num or 0
		return
	end

	self._displayNum = self._num or 0

end

function PetEquipIconNew:SetNumUIVisible()
	local b = self._showNum and self._showNum or false

	if self._uiNumTxtTrans.gameObject.activeSelf ~= b then
		CS.ShowObject(self._uiNumTxtTrans, b)
	end
end

function PetEquipIconNew:ApplyLvTxt()
	if not self._showNum then return end
	local num = self._displayNum
	local numStr = tostring(num)
	if not num or num == -1 then
		numStr = ""
	end
	self:SetXUIText(self._uiNumTxtTrans,numStr)
end


function PetEquipIconNew:SetItemNum(num)
	self._num = num

	self:UpdateNumData()

	if not self:IsIconValid() then return end
	self:ApplyLvTxt()
end

function PetEquipIconNew:SetShowGouImg(b)
	b = b or false and true
	self._showGou = b
end

function PetEquipIconNew:ShowGouImg(b)
	if self._showGou == b then return end
	self._showGou = b

	if not self:IsIconValid() then return end

	self:SetGouTransVisible(self._showGou)
	self:SetEquipIconGray()
end

function PetEquipIconNew:SetGouTransVisible(bVisible)
	bVisible = bVisible and bVisible or false
	local gameObj = self._uiGouTrans.gameObject
	if gameObj.activeSelf ~= bVisible then
		CS.ShowObject(gameObj, bVisible)
	end
end

function PetEquipIconNew:SetEquipIconGray()
	local b = self._showGou
	self:SetImageGray(self._uiIconBgTrans,b)
	self:SetImageGray(self._uiIconTrans,b)
end

function PetEquipIconNew:SetEmptyIconByPart(part)
	local iconPath = self:GetEquipPartRef(part).emptyIcon
	if iconPath then
		self._displayShowIcon = iconPath
		self:SetIcon(self._displayShowIcon)
	end
end
-----------------------------------------------------------------
function PetEquipIconNew:SetData(refId, itemNum, part)
	self._refId = refId
	self._num = itemNum
	local key = self._refId
	local equipRef = self:GetEquipRef(refId)
	local displayNum = 0
	local star = 0
	local bShowNum = self._showNum
	local iconPath = nil
	local iconBgPath = nil
	local itemName = nil
	local itemColor = nil

	self._equipRef = equipRef
	if equipRef then
		iconPath = equipRef.icon

		itemName = ccLngText(equipRef.name)

		local quality = equipRef.quality
		local qualityRef = self:GetItemQualityRef(quality)
		if qualityRef then
			iconBgPath = qualityRef.iconBg
			local color = qualityRef.nameColor
			if color then
				itemColor = LUtil.ColorByHex(color)
			end
		end


		self._isEquip = true
		star = equipRef.star
		self._showNum = itemNum and tonumber(itemNum)>0
	else
		self._isEquip = false
		self._showNum = false
		--self._showGou = false

		iconPath = "public_item_bg_add"
		iconBgPath = "public_item_bg_1"
		if part then
			local partRef = self:GetEquipPartRef(part)
			iconPath = partRef and partRef.emptyIcon or iconPath
		end
	end

	self._displayName = itemName
	self._displayColor = itemColor

	self._displayStar = star
	self._displayShowIcon = iconPath
	self._displayShowIconBg = iconBgPath

	self:UpdateNumData()
end

function PetEquipIconNew:GetNameData()
	return self._displayName,self._displayColor
end

-----------------------------------------------------------------
function PetEquipIconNew:GetEquipRef(refId)

	return GameTable.MagicPetArticleRef[refId]
end

function PetEquipIconNew:GetEquipPartRef(refId)

	return GameTable.MagicPetArticleTypeRef[refId]
end

-----------------------------------------------------------------
return PetEquipIconNew